// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("catalog_get",
			mcplib.WithDescription("Get a vehicle class by slug (business, first, van). Required: slug. Returns the Package."),
			mcplib.WithString("slug", mcplib.Required(), mcplib.Description("Vehicle class slug: business, first, or van")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/packages/{slug}", true, false, nil, []mcpParamBinding{{PublicName: "slug", WireName: "slug", Location: "path"}}, []string{"slug"}),
	)
	s.AddTool(
		mcplib.NewTool("prices_create",
			mcplib.WithDescription("Request prices for a journey (raw body; see 'quote' for a friendly interface). Required: serviceCategory (default: prebooked), serviceType, departAt. Optional: duration. Returns the new PriceResult."),
			mcplib.WithString("serviceCategory", mcplib.Required(), mcplib.Description("Service category (prebooked)")),
			mcplib.WithString("serviceType", mcplib.Required(), mcplib.Description("transfer or hourly")),
			mcplib.WithString("departAt", mcplib.Required(), mcplib.Description("Local pickup datetime, e.g. 2026-06-25T15:00:00")),
			mcplib.WithNumber("duration", mcplib.Description("Hourly only: duration in seconds (hours*3600, min 7200)")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/prices", false, false, nil, []mcpParamBinding{{PublicName: "serviceCategory", WireName: "serviceCategory", Location: "body"}, {PublicName: "serviceType", WireName: "serviceType", Location: "body"}, {PublicName: "departAt", WireName: "departAt", Location: "body"}, {PublicName: "duration", WireName: "duration", Location: "body"}}, []string{}),
	)
	// SQL tool — ad-hoc analysis on synced data without API calls
	s.AddTool(
		mcplib.NewTool("sql",
			mcplib.WithDescription("Run read-only SQL against local database. Use for ad-hoc analysis, aggregations, and joins across synced resources. Requires sync first."),
			mcplib.WithString("query", mcplib.Required(), mcplib.Description("SQL query (SELECT or WITH...SELECT). Tables match resource names.")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleSQL,
	)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Call this first."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleContext,
	)

	// Runtime Cobra-tree mirror — exposes every user-facing command that is
	// not already covered by a typed endpoint or framework MCP tool.
	cobratree.RegisterAll(s, cli.RootCmd(), cobratree.SiblingCLIPath)
}

type mcpParamBinding struct {
	PublicName string
	WireName   string
	Location   string
}

// makeAPIHandler creates a generic MCP tool handler for an API endpoint.
